function createEventTracker() {
  const events = {};
  return {
    track(name) {
      const now = Date.now();
      if (!events[name]) events[name] = { count: 0, first: now, last: now };
      events[name].count++;
      // Bug 1: should update 'last' timestamp but doesn't
    },
    stats(name) {
      const e = events[name];
      if (!e) return null;
      // Bug 2: returns 'first' for both first and last
      return { count: e.count, first: e.first, last: e.first };
    },
    reset(name) { if (name) delete events[name]; else Object.keys(events).forEach(k => delete events[k]); },
  };
}
module.exports = { createEventTracker };

