const assert = require("assert");
const { createEventTracker } = require("../question-05/index.js");
let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log("PASS: " + name); } catch(e) { failed++; console.log("FAIL: " + name + " — " + e.message); } }
runTest("track + stats", () => { const t = createEventTracker(); t.track("click"); const s = t.stats("click"); assert.strictEqual(s.count, 1); });
runTest("last timestamp updates", () => { const t = createEventTracker(); t.track("click"); const first = t.stats("click").first; const start = Date.now(); while(Date.now() - start < 5) {} t.track("click"); const s = t.stats("click"); assert.strictEqual(s.count, 2); assert.ok(s.last > first, "last should be > first"); });
runTest("unknown event", () => { const t = createEventTracker(); assert.strictEqual(t.stats("x"), null); });
runTest("reset single", () => { const t = createEventTracker(); t.track("a"); t.reset("a"); assert.strictEqual(t.stats("a"), null); });
console.log("\n" + passed + "/" + (passed+failed) + " tests passed");
if (failed > 0) process.exit(1);
